def trimmed_mean(nums):
    if not nums:
        return None
    nums.sort()
    median = len(nums) // 2
    if len(nums) % 2 == 0:
        first_quartile, third_quartile = (nums[median-1], nums[median])
    else:
        first_quartile, third_quartile = (nums[median-1], nums[median])
    trimmed_nums = [num for num in nums if num not in (first_quartile, third_quartile)]
    return sum(trimmed_nums) / len(trimmed_nums)
